// n8n Code Node: "FiltraDisponiveis" - Versão 4 (Fonte Única: "Normaliza")
// LÊ todas as configurações de horário e dados de contexto do nó "Normaliza".
// PROCESSA expediente, intervalo de almoço, feriados e eventos da agenda.

// ----- Feriados nacionais 2025–2029 (lista fixa) -----
const HOLIDAYS_BR = [
  {"data":"2025-01-01","nome":"Confraternização Universal"}, {"data":"2025-04-18","nome":"Paixão de Cristo"},
  {"data":"2025-04-21","nome":"Tiradentes"}, {"data":"2025-05-01","nome":"Dia Mundial do Trabalho"},
  {"data":"2025-09-07","nome":"Independência do Brasil"}, {"data":"2025-10-12","nome":"Nossa Senhora Aparecida"},
  {"data":"2025-11-02","nome":"Finados"}, {"data":"2025-11-15","nome":"Proclamação da República"},
  {"data":"2025-11-20","nome":"Dia Nacional de Zumbi e da Consciência Negra"}, {"data":"2025-12-25","nome":"Natal"},
  // ... (manter a lista completa de feriados)
  {"data":"2029-01-01","nome":"Confraternização Universal"}, {"data":"2029-03-30","nome":"Paixão de Cristo"},
  {"data":"2029-04-21","nome":"Tiradentes"}, {"data":"2029-05-01","nome":"Dia Mundial do Trabalho"},
  {"data":"2029-09-07","nome":"Independência do Brasil"}, {"data":"2029-10-12","nome":"Nossa Senhora Aparecida"},
  {"data":"2029-11-02","nome":"Finados"}, {"data":"2029-11-15","nome":"Proclamação da República"},
  {"data":"2029-11-20","nome":"Dia Nacional de Zumbi e da Consciência Negra"}, {"data":"2029-12-25","nome":"Natal"}
];

// ----- Funções Auxiliares -----
function toDateStrFromAny(input) { if (!input) return null; const m = String(input).match(/^(\d{4}-\d{2}-\d{2})/); return m ? m[1] : null; }
function getHHmm(dtStr) { if (!dtStr || typeof dtStr !== 'string') return "00:00"; const parts = dtStr.split('T')[1] || dtStr.split(' ')[1] || "00:00:00"; return parts.slice(0, 5); }
function hhmmToMin(hhmm) { if (!hhmm || !/^\d{2}:\d{2}$/.test(hhmm)) return 0; const [h, m] = hhmm.split(':').map(Number); return (h * 60) + m; }
function minToHHmm(totalMin) { const h = Math.floor(totalMin / 60); const m = totalMin % 60; return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`; }
function overlaps(aStart, aEnd, bStart, bEnd) { return aStart < bEnd && bStart < aEnd; }

// ----- 1. CAPTURA DE DADOS DE ENTRADA -----

// Captura segura dos dados do nó "Normaliza"
let normalizaData = {};
try {
  normalizaData = $items("Normaliza")[0].json;
} catch (e) {
  throw new Error('O nó "Normaliza" não foi encontrado ou está vazio. Verifique o nome e a conexão do nó.');
}

// Captura de eventos da agenda (ex: Google Calendar) que vêm como input principal
const eventsInputRaw = $input.all();
const eventsInput = Array.isArray(eventsInputRaw) ? eventsInputRaw : [];

// ----- 2. DETERMINAÇÃO DA DATA ALVO -----
// Prioriza a data vinda do próprio nó "Normaliza"
let targetDate = toDateStrFromAny(normalizaData.start) || toDateStrFromAny(normalizaData.date) ||
  (() => new Date().toISOString().slice(0, 10))();

// ----- 3. PROCESSAMENTO DAS REGRAS DE HORÁRIO -----

// Mapeia o número do dia da semana (0-6) para a chave do JSON de configuração
const weekdayMap = ["domingo", "segunda-feira", "terça-feira", "quarta-feira", "quinta-feira", "sexta-feira", "sabado"];
const dateObj = new Date(`${targetDate}T12:00:00Z`); // Use Z para UTC e evitar problemas de fuso
const weekdayName = weekdayMap[dateObj.getUTCDay()];

// Extrai as regras para o dia da semana alvo a partir dos dados do "Normaliza"
const daySchedule = normalizaData[weekdayName] || "00:00-00:00/00:00-00:00";
const [workHours, breakHours] = daySchedule.split('/');
const [startWork, endWork] = workHours.split('-');
const [startBreak, endBreak] = (breakHours || "00:00-00:00").split('-');

const SLOT_MINUTES = hhmmToMin(normalizaData.duration || "00:30");
const dayStartMin = hhmmToMin(startWork);
const dayEndMin = hhmmToMin(endWork);
const breakStartMin = hhmmToMin(startBreak);
const breakEndMin = hhmmToMin(endBreak);

// ----- 4. VERIFICAÇÃO DE FERIADOS -----
const holidaysFixedSet = new Set(HOLIDAYS_BR.map(h => h.data));
const holidaysFixedMap = new Map(HOLIDAYS_BR.map(h => [h.data, h.nome]));
// Adiciona feriados extras vindos do próprio nó "Normaliza"
const holidaysExtra = Array.isArray(normalizaData.holidays) ? normalizaData.holidays.map(toDateStrFromAny).filter(Boolean) : [];
holidaysExtra.forEach(d => holidaysFixedSet.add(d));

const isHoliday = holidaysFixedSet.has(targetDate);
const holidayName = isHoliday ? (holidaysFixedMap.get(targetDate) || "Feriado") : null;

// ----- 5. MAPEAMENTO DE BLOQUEIOS (EVENTOS + ALMOÇO) -----

// Normaliza eventos da agenda para o formato de minutos
let booked = eventsInput
  .map(i => i.json || {})
  .filter(ev => ev.start && ev.end && toDateStrFromAny(ev.start.dateTime || ev.start.date) === targetDate)
  .map(ev => ({
    id: ev.id || 'event',
    startMin: hhmmToMin(getHHmm(ev.start.dateTime)),
    endMin: hhmmToMin(getHHmm(ev.end.dateTime)),
    label: `${getHHmm(ev.start.dateTime)}-${getHHmm(ev.end.dateTime)}`,
  }));

// Adiciona o intervalo de almoço à lista de bloqueios, se ele for válido
if (breakStartMin < breakEndMin) {
  booked.push({
    id: 'break-time',
    startMin: breakStartMin,
    endMin: breakEndMin,
    label: `${minToHHmm(breakStartMin)}-${minToHHmm(breakEndMin)} (Almoço)`,
  });
}
booked.sort((a, b) => a.startMin - b.startMin);

// ----- 6. GERAÇÃO E FILTRAGEM DOS SLOTS DISPONÍVEIS -----
const candidateSlots = [];
if (dayStartMin < dayEndMin && !isHoliday) {
  for (let startMin = dayStartMin; startMin + SLOT_MINUTES <= dayEndMin; startMin += SLOT_MINUTES) {
    candidateSlots.push({ startMin: startMin, endMin: startMin + SLOT_MINUTES });
  }
}

const available = candidateSlots.filter(slot =>
  !booked.some(b => overlaps(b.startMin, b.endMin, slot.startMin, slot.endMin))
);

// ----- 7. FORMATAÇÃO DA SAÍDA -----
const result = {
  date: targetDate,
  timezone: "America/Sao_Paulo",
  weekday: weekdayName,
  isHoliday: isHoliday,
  holidayName: holidayName,
  workingHours: {
    start: startWork,
    end: endWork,
    break: (breakStartMin < breakEndMin) ? `${startBreak}-${endBreak}` : null,
  },
  slotDurationMinutes: SLOT_MINUTES,
  bookedSlots: booked.map(b => ({ id: b.id, label: b.label })),
  availableSlots: available.map(s => ({
    start: `${targetDate}T${minToHHmm(s.startMin)}:00-03:00`,
    end: `${targetDate}T${minToHHmm(s.endMin)}:00-03:00`,
    label: `${minToHHmm(s.startMin)}-${minToHHmm(s.endMin)}`,
  })),
};

return [{ json: result }];
